// NeuroNest API Client

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

export interface ChatMessage {
  role: "user" | "assistant";
  content: string;
}

export interface ActivitySuggestion {
  title: string;
  description: string;
  duration: string;
  category: string;
  emoji: string;
}

export interface ChatResponse {
  response: string;
  detected_emotion: string;
  mood_level: string;
  activities: ActivitySuggestion[];
  special_action: string | null;
  special_content: string | null;
  session_id: string;
  wellness_tip: string | null;
}

export interface VoiceAnalysisResponse {
  transcribed_text: string;
  detected_emotion: string;
  mood_level: string;
  confidence: number;
  chat_response: ChatResponse;
}

export interface MoodCheckInResponse {
  message: string;
  activities: ActivitySuggestion[];
  wellness_tip: string;
}

// Send a text chat message
export async function sendChatMessage(
  message: string,
  history: ChatMessage[],
  sessionId?: string
): Promise<ChatResponse> {
  const res = await fetch(`${API_BASE}/api/chat/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      message,
      conversation_history: history,
      session_id: sessionId,
    }),
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Failed to send message");
  }

  return res.json();
}

// Upload audio for voice analysis
export async function analyzeVoice(
  audioBlob: Blob,
  sessionId?: string
): Promise<VoiceAnalysisResponse> {
  const formData = new FormData();
  formData.append("audio", audioBlob, "recording.webm");
  if (sessionId) formData.append("session_id", sessionId);

  const res = await fetch(`${API_BASE}/api/voice/analyze`, {
    method: "POST",
    body: formData,
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Voice analysis failed");
  }

  return res.json();
}

// Submit mood check-in
export async function submitMoodCheckIn(
  userId: string,
  moodLevel: string,
  emotions: string[],
  note?: string
): Promise<MoodCheckInResponse> {
  const res = await fetch(`${API_BASE}/api/mood/checkin`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ user_id: userId, mood_level: moodLevel, emotions, note }),
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Mood check-in failed");
  }

  return res.json();
}
